INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('5ad4cdc0-90c3-4453-aab2-64d50f75c178', 'Dạng bài ''Causes and Solutions'' (Nguyên nhân & Giải pháp) yêu cầu tính logic (Cause-Effect match) như thế nào?', 'multiple_choice', '["Liệt kê càng nhiều nguyên nhân càng tốt.","Các Giải pháp đề xuất ở Đoạn 2 bắt buộc phải NHẮM TRỰC TIẾP vào việc triệt tiêu hoặc cải thiện các Nguyên nhân đã được xác định ở Đoạn 1.","Nguyên nhân và giải pháp không cần liên quan đến nhau.","Giải pháp phải được thực hiện trong quá khứ."]', 'Các Giải pháp đề xuất ở Đoạn 2 bắt buộc phải NHẮM TRỰC TIẾP vào việc triệt tiêu hoặc cải thiện các Nguyên nhân đã được xác định ở Đoạn 1.', 'Tính mạch lạc (Coherence) nằm ở sự tương thích. Nếu nguyên nhân béo phì là ''ăn fast-food'', giải pháp phải là ''đánh thuế fast-food'', chứ không thể là ''cấm bán xe máy''.'),
('5ad4cdc0-90c3-4453-aab2-64d50f75c178', 'Khi mở đầu đoạn văn về Nguyên nhân, cụm từ học thuật nào sau đây là chuyên nghiệp nhất?', 'multiple_choice', '["There are some reasons why this happens.","This phenomenon can be attributed to several underlying factors.","Because of this...","I will tell you the causes now."]', 'This phenomenon can be attributed to several underlying factors.', 'Cụm ''be attributed to'' (được quy cho/có nguyên nhân từ) và ''underlying factors'' (các yếu tố sâu xa) nâng Band điểm từ vựng của bạn lên mức 7.0+.'),
('5ad4cdc0-90c3-4453-aab2-64d50f75c178', 'Để đề xuất giải pháp, cấu trúc ngữ pháp nào thường được sử dụng phổ biến và mang tính khách quan (Objective tone)?', 'multiple_choice', '["You should...","We must...","To tackle this issue, several feasible measures should be implemented by...","I order the government to..."]', 'To tackle this issue, several feasible measures should be implemented by...', 'Việc sử dụng câu bị động (Passive voice) với Modal verbs (should be implemented) là chuẩn mực của Academic Writing khi đưa ra khuyến nghị.'),
('a8b5cec3-24e3-43c0-8248-9062bfd39d5f', 'Dạng bài ''Two-part Questions'' (Đề bài có 2 câu hỏi trực tiếp) yêu cầu cấu trúc bài viết như thế nào?', 'multiple_choice', '["Gộp chung trả lời cho 2 câu vào 1 đoạn văn duy nhất.","Bỏ qua câu hỏi khó, chỉ trả lời câu dễ.","Mỗi câu hỏi phải được trả lời và phát triển trọn vẹn trong một đoạn Thân bài riêng biệt (Body 1 trả lời câu 1, Body 2 trả lời câu 2).","Chỉ trả lời ở phần Kết luận."]', 'Mỗi câu hỏi phải được trả lời và phát triển trọn vẹn trong một đoạn Thân bài riêng biệt (Body 1 trả lời câu 1, Body 2 trả lời câu 2).', 'Bất kỳ sự mất cân đối nào (ví dụ: viết quá dài cho câu 1 mà chỉ viết 2 dòng cho câu 2) sẽ khiến bạn bị phạt lỗi Task Response do không trả lời đầy đủ các phần của đề bài.'),
('a8b5cec3-24e3-43c0-8248-9062bfd39d5f', 'Ở phần Mở bài của dạng Two-part questions, câu Thesis Statement của bạn phải chứa thông tin gì?', 'multiple_choice', '["Chỉ cần nói ''I will discuss this in my essay''.","Phải tóm tắt ngắn gọn câu trả lời cho CẢ HAI câu hỏi một cách trực diện.","Không cần Thesis Statement.","Chỉ trả lời câu hỏi thứ nhất."]', 'Phải tóm tắt ngắn gọn câu trả lời cho CẢ HAI câu hỏi một cách trực diện.', 'Giám khảo cần thấy được ''Roadmap'' của bạn. Bạn không nên giấu câu trả lời. Hãy đưa ra câu trả lời cốt lõi ngay từ Mở bài.'),
('a8b5cec3-24e3-43c0-8248-9062bfd39d5f', 'Nếu câu hỏi 1 hỏi về ''Why'' (Nguyên nhân) và câu hỏi 2 hỏi về ''Positive or Negative'' (Đánh giá), bài viết của bạn sẽ kết hợp tính chất của hai dạng bài nào?', 'multiple_choice', '["Cause & Solution và Opinion.","Không có dạng bài nào.","Cause & Effect và Discussion.","Cause (Nguyên nhân) và Opinion (Luận điểm đánh giá)."]', 'Cause (Nguyên nhân) và Opinion (Luận điểm đánh giá).', 'Two-part questions bản chất là sự ''lai tạo'' (hybrid) của các dạng bài cơ bản. Bạn phải linh hoạt áp dụng cách viết của từng dạng cho từng đoạn văn tương ứng.'),
('0bf00e78-b294-41b8-ad1e-1bf760e4c848', 'Tiêu chí ''Grammatical Range and Accuracy'' (GRA) để đạt Band 7.0+ yêu cầu điều gì?', 'multiple_choice', '["Sử dụng 100% câu đơn để tránh mọi lỗi sai chính tả.","Sử dụng chính xác và linh hoạt sự kết hợp giữa câu đơn và các cấu trúc câu phức (Complex structures như Mệnh đề quan hệ, Câu điều kiện, Bị động), chấp nhận một vài lỗi nhỏ không ảnh hưởng đến nghĩa.","Không được mắc bất kỳ một lỗi ngữ pháp nào dù là nhỏ nhất.","Dùng thật nhiều dấu chấm phẩy."]', 'Sử dụng chính xác và linh hoạt sự kết hợp giữa câu đơn và các cấu trúc câu phức (Complex structures như Mệnh đề quan hệ, Câu điều kiện, Bị động), chấp nhận một vài lỗi nhỏ không ảnh hưởng đến nghĩa.', 'IELTS đánh giá cao sự đa dạng (Range). Việc dám thử sức với câu phức tạo ra giá trị cao hơn là chỉ thu mình viết câu đơn an toàn.'),
('0bf00e78-b294-41b8-ad1e-1bf760e4c848', 'Trong tiêu chí Lexical Resource, cụm từ ''Uncommon lexical items'' nghĩa là gì?', 'multiple_choice', '["Những từ vựng cổ xưa từ thế kỷ 16 không ai dùng nữa.","Những từ vựng dài nhất trong từ điển.","Những từ vựng, Collocations, và Idiomatic expressions mang tính học thuật, chính xác với ngữ cảnh chủ đề, mà người dùng cơ bản thường ít biết đến (ví dụ: ''mitigate'' thay vì ''reduce'').","Những từ tự bịa ra."]', 'Những từ vựng, Collocations, và Idiomatic expressions mang tính học thuật, chính xác với ngữ cảnh chủ đề, mà người dùng cơ bản thường ít biết đến (ví dụ: ''mitigate'' thay vì ''reduce'').', 'Dùng từ ''hiếm'' nhưng sai ngữ cảnh (inappropriate context) sẽ kéo điểm bạn xuống Band 5. Từ vựng ăn điểm phải là ''Uncommon'' nhưng được dùng cực kỳ tự nhiên (Natural).'),
('0bf00e78-b294-41b8-ad1e-1bf760e4c848', 'Việc lạm dụng quá mức (Overuse) các từ nối (Linking words như Furthermore, Moreover, Consequently) ở đầu mọi câu văn sẽ gây ra vấn đề gì đối với tiêu chí Coherence & Cohesion?', 'multiple_choice', '["Giúp đạt Band 9.0 dễ dàng.","Gây ra hiện tượng ''Mechanical Cohesion'' (Liên kết máy móc/thiếu tự nhiên), làm bài văn trở nên nặng nề và bị trừ điểm.","Làm cho ngữ pháp tốt hơn.","Làm giám khảo vui vẻ."]', 'Gây ra hiện tượng ''Mechanical Cohesion'' (Liên kết máy móc/thiếu tự nhiên), làm bài văn trở nên nặng nề và bị trừ điểm.', 'Sự liên kết đỉnh cao (Band 8+) là sự liên kết bằng Đại từ thay thế (This, That, These issues) và sự trôi chảy của logic, chứ không phải nhồi nhét quá nhiều từ nối.'),
('6f13fe92-980d-4abe-a824-182583e4d720', 'Thời lượng khuyên dùng tối ưu để phân bổ cho Writing Task 2 trong tổng thời gian 60 phút của phần thi Writing là bao nhiêu?', 'multiple_choice', '["20 phút.","30 phút.","40 phút (gấp đôi thời gian của Task 1 vì Task 2 chiếm 2/3 tổng số điểm Writing).","60 phút."]', '40 phút (gấp đôi thời gian của Task 1 vì Task 2 chiếm 2/3 tổng số điểm Writing).', 'Đừng bao giờ ăn lẹm thời gian của Task 2 cho Task 1. Một bài Task 2 dang dở sẽ kéo sập toàn bộ điểm thi Writing của bạn.'),
('6f13fe92-980d-4abe-a824-182583e4d720', 'Trong 40 phút làm Task 2, thời gian dành cho bước Lập dàn ý (Planning) và Rà soát lỗi (Proofreading) nên được phân bổ như thế nào?', 'multiple_choice', '["Bỏ qua cả hai bước này để viết liên tục 40 phút.","Khoảng 5 phút đầu để phân tích đề & lập dàn ý chi tiết, và 3-5 phút cuối cùng để đọc lại sửa lỗi chính tả/ngữ pháp nhỏ.","30 phút lập dàn ý, 10 phút viết.","Lập dàn ý sau khi đã viết xong."]', 'Khoảng 5 phút đầu để phân tích đề & lập dàn ý chi tiết, và 3-5 phút cuối cùng để đọc lại sửa lỗi chính tả/ngữ pháp nhỏ.', '5 phút planning giúp bạn không bao giờ bị ''bí ý'' hoặc đi lạc đề giữa chừng. 3 phút proofreading giúp bạn cứu vớt 0.5 Band bằng cách sửa các lỗi số nhiều/số ít, mạo từ (a/an/the) vô ý.'),
('6f13fe92-980d-4abe-a824-182583e4d720', 'Số lượng từ (Word count) lý tưởng nhất cho IELTS Writing Task 2 để đảm bảo phát triển ý sâu sắc mà không bị trừ điểm vì lan man là bao nhiêu?', 'multiple_choice', '["Dưới 250 từ.","Chính xác 250 từ.","Khoảng 260 đến 300 từ.","Trên 500 từ."]', 'Khoảng 260 đến 300 từ.', 'Viết dưới 250 từ sẽ bị phạt nặng (Underlength penalty). Viết quá dài (hơn 350 từ) làm tăng nguy cơ sai ngữ pháp, lạc đề và mất thời gian soát lỗi. Mức 270-280 từ là con số vàng.');